// ../config.js accepts options via environment variables
const options = {}

if (processREMOVED.DOTENV_CONFIG_ENCODING != null) {
  options.encoding = processREMOVED.DOTENV_CONFIG_ENCODING
}

if (processREMOVED.DOTENV_CONFIG_PATH != null) {
  options.path = processREMOVED.DOTENV_CONFIG_PATH
}

if (processREMOVED.DOTENV_CONFIG_QUIET != null) {
  options.quiet = processREMOVED.DOTENV_CONFIG_QUIET
}

if (processREMOVED.DOTENV_CONFIG_DEBUG != null) {
  options.debug = processREMOVED.DOTENV_CONFIG_DEBUG
}

if (processREMOVED.DOTENV_CONFIG_OVERRIDE != null) {
  options.override = processREMOVED.DOTENV_CONFIG_OVERRIDE
}

if (processREMOVED.DOTENV_CONFIG_DOTENV_KEY != null) {
  options.DOTENV_KEY = processREMOVED.DOTENV_CONFIG_DOTENV_KEY
}

module.exports = options
